1	/**
2	 * Context compaction for long sessions.
3	 *
4	 * Pure functions for compaction logic. The session manager handles I/O,
5	 * and after compaction the session is reloaded.
6	 */
7	import type { AgentMessage } from "@oh-my-pi/pi-agent-core";
8	import {
9		type AssistantMessage,
10		completeSimple,
11		Effort,
12		type MessageAttribution,
13		type Model,
14		type Usage,
15	} from "@oh-my-pi/pi-ai";
16	import {
17		CODEX_BASE_URL,
18		getCodexAccountId,
19		OPENAI_HEADER_VALUES,
20		OPENAI_HEADERS,
21	} from "@oh-my-pi/pi-ai/providers/openai-codex/constants";
22	import { parseTextSignature } from "@oh-my-pi/pi-ai/providers/openai-responses-shared";
23	import { transformMessages } from "@oh-my-pi/pi-ai/providers/transform-messages";
24	import {
25		getOpenAIResponsesHistoryItems,
26		getOpenAIResponsesHistoryPayload,
27		normalizeResponsesToolCallId,
28	} from "@oh-my-pi/pi-ai/utils";
29	import { logger } from "@oh-my-pi/pi-utils";
30	import { renderPromptTemplate } from "../../config/prompt-templates";
31	import compactionShortSummaryPrompt from "../../prompts/compaction/compaction-short-summary.md" with { type: "text" };
32	import compactionSummaryPrompt from "../../prompts/compaction/compaction-summary.md" with { type: "text" };
33	import compactionTurnPrefixPrompt from "../../prompts/compaction/compaction-turn-prefix.md" with { type: "text" };
34	import compactionUpdateSummaryPrompt from "../../prompts/compaction/compaction-update-summary.md" with { type: "text" };
35	import { convertToLlm, createBranchSummaryMessage, createCustomMessage } from "../../session/messages";
36	import type { CompactionEntry, SessionEntry } from "../../session/session-manager";
37	
38	import {
39		computeFileLists,
40		createFileOps,
41		extractFileOpsFromMessage,
42		type FileOperations,
43		SUMMARIZATION_SYSTEM_PROMPT,
44		serializeConversation,
45		upsertFileOperations,
46	} from "./utils";
47	
48	// ============================================================================
49	// File Operation Tracking
50	// ============================================================================
51	
52	/** Details stored in CompactionEntry.details for file tracking */
53	export interface CompactionDetails {
54		readFiles: string[];
55		modifiedFiles: string[];
56	}
57	
58	/**
59	 * Extract file operations from messages and previous compaction entries.
60	 */
61	function extractFileOperations(
62		messages: AgentMessage[],
63		entries: SessionEntry[],
64		prevCompactionIndex: number,
65	): FileOperations {
66		const fileOps = createFileOps();
67	
68		// Collect from previous compaction's details (if pi-generated)
69		if (prevCompactionIndex >= 0) {
70			const prevCompaction = entries[prevCompactionIndex] as CompactionEntry;
71			if (!prevCompaction.fromExtension && prevCompaction.details) {
72				const details = prevCompaction.details as CompactionDetails;
73				if (Array.isArray(details.readFiles)) {
74					for (const f of details.readFiles) fileOps.read.add(f);
75				}
76				if (Array.isArray(details.modifiedFiles)) {
77					for (const f of details.modifiedFiles) fileOps.edited.add(f);
78				}
79			}
80		}
81	
82		// Extract from tool calls in messages
83		for (const msg of messages) {
84			extractFileOpsFromMessage(msg, fileOps);
85		}
86	
87		return fileOps;
88	}
89	
90	// ============================================================================
91	// Message Extraction
92	// ============================================================================
93	
94	/**
95	 * Extract AgentMessage from an entry if it produces one.
96	 * Returns undefined for entries that don't contribute to LLM context.
97	 */
98	function getMessageFromEntry(entry: SessionEntry): AgentMessage | undefined {
99		if (entry.type === "message") {
100			return entry.message;
101		}
102		if (entry.type === "custom_message") {
103			return createCustomMessage(
104				entry.customType,
105				entry.content,
106				entry.display,
107				entry.details,
108				entry.timestamp,
109				entry.attribution,
110			);
111		}
112		if (entry.type === "branch_summary") {
113			return createBranchSummaryMessage(entry.summary, entry.fromId, entry.timestamp);
114		}
115		return undefined;
116	}
117	
118	/** Result from compact() - SessionManager adds uuid/parentUuid when saving */
119	export interface CompactionResult<T = unknown> {
120		summary: string;
121		/** Short PR-style summary for display purposes. */
122		shortSummary?: string;
123		firstKeptEntryId: string;
124		tokensBefore: number;
125		/** Hook-specific data (e.g., ArtifactIndex, version markers for structured compaction) */
126		details?: T;
127		/** Hook-provided data to persist alongside compaction entry. */
128		preserveData?: Record<string, unknown>;
129	}
130	
131	// ============================================================================
132	// Types
133	// ============================================================================
134	
135	export interface CompactionSettings {
136		enabled: boolean;
137		strategy?: "context-full" | "handoff" | "off";
138		thresholdPercent?: number;
139		thresholdTokens?: number;
140		reserveTokens: number;
141		keepRecentTokens: number;
142		autoContinue?: boolean;
143		remoteEnabled?: boolean;
144		remoteEndpoint?: string;
145	}
146	
147	export const DEFAULT_COMPACTION_SETTINGS: CompactionSettings = {
148		enabled: true,
149		strategy: "context-full",
150		thresholdPercent: -1,
151		thresholdTokens: -1,
152		reserveTokens: 16384,
153		keepRecentTokens: 20000,
154		autoContinue: true,
155		remoteEnabled: true,
156	};
157	
158	// ============================================================================
159	// Token calculation
160	// ============================================================================
161	
162	/**
163	 * Calculate total context tokens from usage.
164	 * Uses the native totalTokens field when available, falls back to computing from components.
165	 */
166	export function calculateContextTokens(usage: Usage): number {
167		return usage.totalTokens || usage.input + usage.output + usage.cacheRead + usage.cacheWrite;
168	}
169	
170	export function calculatePromptTokens(usage: Usage): number {
171		const promptTokens = usage.input + usage.cacheRead + usage.cacheWrite;
172		if (promptTokens > 0) {
173			return promptTokens;
174		}
175		return calculateContextTokens(usage);
176	}
177	
178	/**
179	 * Get usage from an assistant message if available.
180	 * Skips aborted and error messages as they don't have valid usage data.
181	 */
182	function getAssistantUsage(msg: AgentMessage): Usage | undefined {
183		if (msg.role === "assistant" && "usage" in msg) {
184			const assistantMsg = msg as AssistantMessage;
185			if (assistantMsg.stopReason !== "aborted" && assistantMsg.stopReason !== "error" && assistantMsg.usage) {
186				return assistantMsg.usage;
187			}
188		}
189		return undefined;
190	}
191	
192	/**
193	 * Find the last non-aborted assistant message usage from session entries.
194	 */
195	export function getLastAssistantUsage(entries: SessionEntry[]): Usage | undefined {
196		for (let i = entries.length - 1; i >= 0; i--) {
197			const entry = entries[i];
198			if (entry.type === "message") {
199				const usage = getAssistantUsage(entry.message);
200				if (usage) return usage;
201			}
202		}
203		return undefined;
204	}
205	
206	/**
207	 * Effective reserve: at least 15% of context window or the configured floor, whichever is larger.
208	 */
209	export function effectiveReserveTokens(contextWindow: number, settings: CompactionSettings): number {
210		return Math.max(Math.floor(contextWindow * 0.15), settings.reserveTokens);
211	}
212	
213	/**
214	 * Check if compaction should trigger based on context usage.
215	 */
216	export function shouldCompact(contextTokens: number, contextWindow: number, settings: CompactionSettings): boolean {
217		if (!settings.enabled || settings.strategy === "off" || contextWindow <= 0) return false;
218		const thresholdTokens = resolveThresholdTokens(contextWindow, settings);
219		return contextTokens > thresholdTokens;
220	}
221	
222	function resolveThresholdTokens(contextWindow: number, settings: CompactionSettings): number {
223		// Fixed token limit takes priority over percentage
224		const thresholdTokens = settings.thresholdTokens;
225		if (typeof thresholdTokens === "number" && Number.isFinite(thresholdTokens) && thresholdTokens > 0) {
226			// Clamp to [1, contextWindow - 1] so there's always room
227			return Math.min(contextWindow - 1, Math.max(1, thresholdTokens));
228		}
229	
230		// Percentage-based threshold
231		const thresholdPercent = settings.thresholdPercent;
232		if (typeof thresholdPercent !== "number" || !Number.isFinite(thresholdPercent) || thresholdPercent <= 0) {
233			return contextWindow - effectiveReserveTokens(contextWindow, settings);
234		}
235		const clampedThresholdPercent = Math.min(99, Math.max(1, thresholdPercent));
236		return Math.floor(contextWindow * (clampedThresholdPercent / 100));
237	}
238	
239	// ============================================================================
240	// Cut point detection
241	// ============================================================================
242	
243	/**
244	 * Estimate token count for a message using chars/4 heuristic.
245	 * This is conservative (overestimates tokens).
246	 */
247	export function estimateTokens(message: AgentMessage): number {
248		let chars = 0;
249	
250		switch (message.role) {
251			case "user": {
252				const content = (message as { content: string | Array<{ type: string; text?: string }> }).content;
253				if (typeof content === "string") {
254					chars = content.length;
255				} else if (Array.isArray(content)) {
256					for (const block of content) {
257						if (block.type === "text" && block.text) {
258							chars += block.text.length;
259						}
260					}
261				}
262				return Math.ceil(chars / 4);
263			}
264			case "assistant": {
265				const assistant = message as AssistantMessage;
266				for (const block of assistant.content) {
267					if (block.type === "text") {
268						chars += block.text.length;
269					} else if (block.type === "thinking") {
270						chars += block.thinking.length;
271					} else if (block.type === "toolCall") {
272						chars += block.name.length + JSON.stringify(block.arguments).length;
273					}
274				}
275				return Math.ceil(chars / 4);
276			}
277			case "hookMessage":
278			case "toolResult": {
279				if (typeof message.content === "string") {
280					chars = message.content.length;
281				} else {
282					for (const block of message.content) {
283						if (block.type === "text" && block.text) {
284							chars += block.text.length;
285						}
286						if (block.type === "image") {
287							chars += 4800; // Estimate images as 4000 chars, or 1200 tokens
288						}
289					}
290				}
291				return Math.ceil(chars / 4);
292			}
293			case "bashExecution": {
294				chars = message.command.length + message.output.length;
295				return Math.ceil(chars / 4);
296			}
297			case "branchSummary":
298			case "compactionSummary": {
299				chars = message.summary.length;
300				return Math.ceil(chars / 4);
301			}
302		}
303	
304		return 0;
305	}
306	
307	function estimateEntriesTokens(entries: SessionEntry[], startIndex: number, endIndex: number): number {
308		let total = 0;
309		for (let i = startIndex; i < endIndex; i++) {
310			const msg = getMessageFromEntry(entries[i]);
311			if (msg) {
312				total += estimateTokens(msg);
313			}
314		}
315		return total;
316	}
317	
318	/**
319	 * Find valid cut points: indices of user, assistant, custom, or bashExecution messages.
320	 * Never cut at tool results (they must follow their tool call).
321	 * When we cut at an assistant message with tool calls, its tool results follow it
322	 * and will be kept.
323	 * BashExecutionMessage is treated like a user message (user-initiated context).
324	 */
325	function findValidCutPoints(entries: SessionEntry[], startIndex: number, endIndex: number): number[] {
326		const cutPoints: number[] = [];
327		for (let i = startIndex; i < endIndex; i++) {
328			const entry = entries[i];
329			switch (entry.type) {
330				case "message": {
331					const role = entry.message.role;
332					switch (role) {
333						case "bashExecution":
334						case "hookMessage":
335						case "branchSummary":
336						case "compactionSummary":
337						case "user":
338						case "assistant":
339							cutPoints.push(i);
340							break;
341						case "toolResult":
342							break;
343					}
344					break;
345				}
346				case "thinking_level_change":
347				case "model_change":
348				case "compaction":
349				case "branch_summary":
350				case "custom":
351				case "custom_message":
352				case "label":
353			}
354			// branch_summary and custom_message are user-role messages, valid cut points
355			if (entry.type === "branch_summary" || entry.type === "custom_message") {
356				cutPoints.push(i);
357			}
358		}
359		return cutPoints;
360	}
361	
362	/**
363	 * Find the user message (or bashExecution) that starts the turn containing the given entry index.
364	 * Returns -1 if no turn start found before the index.
365	 * BashExecutionMessage is treated like a user message for turn boundaries.
366	 */
367	export function findTurnStartIndex(entries: SessionEntry[], entryIndex: number, startIndex: number): number {
368		for (let i = entryIndex; i >= startIndex; i--) {
369			const entry = entries[i];
370			// branch_summary and custom_message are user-role messages, can start a turn
371			if (entry.type === "branch_summary" || entry.type === "custom_message") {
372				return i;
373			}
374			if (entry.type === "message") {
375				const role = entry.message.role;
376				if (role === "user" || role === "bashExecution") {
377					return i;
378				}
379			}
380		}
381		return -1;
382	}
383	
384	export interface CutPointResult {
385		/** Index of first entry to keep */
386		firstKeptEntryIndex: number;
387		/** Index of user message that starts the turn being split, or -1 if not splitting */
388		turnStartIndex: number;
389		/** Whether this cut splits a turn (cut point is not a user message) */
390		isSplitTurn: boolean;
391	}
392	
393	/**
394	 * Find the cut point in session entries that keeps approximately `keepRecentTokens`.
395	 *
396	 * Algorithm: Walk backwards from newest, accumulating estimated message sizes.
397	 * Stop when we've accumulated >= keepRecentTokens. Cut at that point.
398	 *
399	 * Can cut at user OR assistant messages (never tool results). When cutting at an
400	 * assistant message with tool calls, its tool results come after and will be kept.
401	 *
402	 * Returns CutPointResult with:
403	 * - firstKeptEntryIndex: the entry index to start keeping from
404	 * - turnStartIndex: if cutting mid-turn, the user message that started that turn
405	 * - isSplitTurn: whether we're cutting in the middle of a turn
406	 *
407	 * Only considers entries between `startIndex` and `endIndex` (exclusive).
408	 */
409	export function findCutPoint(
410		entries: SessionEntry[],
411		startIndex: number,
412		endIndex: number,
413		keepRecentTokens: number,
414	): CutPointResult {
415		const cutPoints = findValidCutPoints(entries, startIndex, endIndex);
416	
417		if (cutPoints.length === 0) {
418			return { firstKeptEntryIndex: startIndex, turnStartIndex: -1, isSplitTurn: false };
419		}
420	
421		// Walk backwards from newest, accumulating estimated message sizes
422		let accumulatedTokens = 0;
423		let cutIndex = cutPoints[0]; // Default: keep from first message (not header)
424	
425		for (let i = endIndex - 1; i >= startIndex; i--) {
426			const entry = entries[i];
427			if (entry.type !== "message") continue;
428	
429			// Estimate this message's size
430			const messageTokens = estimateTokens(entry.message);
431			accumulatedTokens += messageTokens;
432	
433			// Check if we've exceeded the budget
434			if (accumulatedTokens >= keepRecentTokens) {
435				// Find the closest valid cut point at or after this entry
436				for (let c = 0; c < cutPoints.length; c++) {
437					if (cutPoints[c] >= i) {
438						cutIndex = cutPoints[c];
439						break;
440					}
441				}
442				break;
443			}
444		}
445	
446		// Scan backwards from cutIndex to include any non-message entries (bash, settings, etc.)
447		while (cutIndex > startIndex) {
448			const prevEntry = entries[cutIndex - 1];
449			// Stop at session header or compaction boundaries
450			if (prevEntry.type === "compaction") {
451				break;
452			}
453			if (prevEntry.type === "message") {
454				// Stop if we hit any message
455				break;
456			}
457			// Include this non-message entry (bash, settings change, etc.)
458			cutIndex--;
459		}
460	
461		// Determine if this is a split turn
462		const cutEntry = entries[cutIndex];
463		const isUserMessage = cutEntry.type === "message" && cutEntry.message.role === "user";
464		const turnStartIndex = isUserMessage ? -1 : findTurnStartIndex(entries, cutIndex, startIndex);
465	
466		return {
467			firstKeptEntryIndex: cutIndex,
468			turnStartIndex,
469			isSplitTurn: !isUserMessage && turnStartIndex !== -1,
470		};
471	}
