525		const defaultBase = "https://api.openai.com/v1";
526		const rawBase = model.baseUrl && model.baseUrl.length > 0 ? model.baseUrl : defaultBase;
527		const normalizedBase = rawBase.endsWith("/") ? rawBase.slice(0, -1) : rawBase;
528		if (normalizedBase.endsWith("/v1")) return `${normalizedBase}/responses/compact`;
