544	function getPreservedOpenAiRemoteCompactionData(
545		preserveData: Record<string, unknown> | undefined,
546	): OpenAiRemoteCompactionPreserveData | undefined {
547		const candidate = preserveData?.[OPENAI_REMOTE_COMPACTION_PRESERVE_KEY];
548		if (!candidate || typeof candidate !== "object") return undefined;
549		const maybeData = candidate as { provider?: unknown; replacementHistory?: unknown; compactionItem?: unknown };
550		if (!Array.isArray(maybeData.replacementHistory)) return undefined;
551		const maybeItem = maybeData.compactionItem;
552		if (!maybeItem || typeof maybeItem !== "object") return undefined;
553		const compactionItem = maybeItem as { type?: unknown; encrypted_content?: unknown; summary?: unknown };
554		const isClassicCompaction =
555			compactionItem.type === "compaction" && typeof compactionItem.encrypted_content === "string";
556		const isSummaryCompaction = compactionItem.type === "compaction_summary";
557		if (!isClassicCompaction && !isSummaryCompaction) {
558			return undefined;
559		}
560		return {
561			provider: typeof maybeData.provider === "string" ? maybeData.provider : undefined,
562			replacementHistory: maybeData.replacementHistory as Array<Record<string, unknown>>,
563			compactionItem: compactionItem as unknown as OpenAiRemoteCompactionItem,
564		};
565	}
