567	function withOpenAiRemoteCompactionPreserveData(
568		preserveData: Record<string, unknown> | undefined,
569		remoteCompaction: OpenAiRemoteCompactionPreserveData | undefined,
570	): Record<string, unknown> | undefined {
571		if (remoteCompaction) {
572			return {
573				...(preserveData ?? {}),
574				[OPENAI_REMOTE_COMPACTION_PRESERVE_KEY]: remoteCompaction,
575			};
576		}
577	
578		if (!preserveData || !(OPENAI_REMOTE_COMPACTION_PRESERVE_KEY in preserveData)) {
579			return preserveData;
580		}
581	
582		const { [OPENAI_REMOTE_COMPACTION_PRESERVE_KEY]: _removed, ...rest } = preserveData;
583		return Object.keys(rest).length > 0 ? rest : undefined;
584	}
