586	function estimateOpenAiCompactInputTokens(input: Array<Record<string, unknown>>, instructions: string): number {
587		let chars = instructions.length;
588		for (const item of input) {
589			chars += JSON.stringify(item).length;
590		}
591		return Math.ceil(chars / 4);
592	}
593	
594	function shouldTrimOpenAiCompactInputItem(item: Record<string, unknown>): boolean {
595		return item.type === "function_call_output" || (item.type === "message" && item.role === "developer");
596	}
597	
598	function shouldKeepOpenAiCompactOutputUserMessage(item: Record<string, unknown>): boolean {
599		if (item.role !== "user") return false;
600		const content = item.content;
601		if (!Array.isArray(content) || content.length === 0) return false;
602		const contextualFragmentPatterns = [
603			[/^<system-reminder>[\s\S]*<\/system-reminder>$/i, /<system-reminder>/i],
604			[/^#\s*AGENTS\.md instructions for\b[\s\S]*<\/INSTRUCTIONS>$/i, /# AGENTS.md instructions/],
605			[/^<environment-context>[\s\S]*<\/environment-context>$/i, /<environment-context>/i],
606			[/^<skill>[\s\S]*<\/skill>$/i, /<skill>/i],
607			[/^<user-shell-command>[\s\S]*<\/user-shell-command>$/i, /<user-shell-command>/i],
608			[/^<turn-aborted>[\s\S]*<\/turn-aborted>$/i, /<turn-aborted>/i],
609			[/^<subagent-notification>[\s\S]*<\/subagent-notification>$/i, /<subagent-notification>/i],
610		] as const;
611		return content.every(part => {
612			if (!part || typeof part !== "object") return false;
613			const candidate = part as { type?: unknown; text?: unknown };
614			if (candidate.type === "input_image") return true;
615			if (candidate.type !== "input_text" || typeof candidate.text !== "string") return false;
616			const trimmed = candidate.text.trim();
617			if (trimmed.length === 0) return false;
618			return !contextualFragmentPatterns.some(([strictPattern, markerPattern]) => {
619				return strictPattern.test(trimmed) || markerPattern.test(trimmed);
620			});
621		});
622	}
623	
624	function shouldKeepOpenAiCompactOutputItem(item: Record<string, unknown>): boolean {
625		if (item.type === "compaction" || item.type === "compaction_summary") return true;
626		if (item.type !== "message") return false;
627		if (item.role === "developer") return false;
628		if (item.role === "assistant") return true;
629		return shouldKeepOpenAiCompactOutputUserMessage(item);
630	}
631	
632	function trimOpenAiCompactInput(
633		input: Array<Record<string, unknown>>,
634		contextWindow: number,
635		instructions: string,
636	): Array<Record<string, unknown>> {
637		const trimmed = [...input];
638		while (trimmed.length > 0 && estimateOpenAiCompactInputTokens(trimmed, instructions) > contextWindow) {
639			const last = trimmed[trimmed.length - 1];
640			if (last?.type === "function_call_output") {
641				const callId = typeof last.call_id === "string" ? last.call_id : undefined;
642				trimmed.pop();
643				if (callId) {
644					const matchingCallIndex = trimmed.findLastIndex(
645						item => item.type === "function_call" && item.call_id === callId,
646					);
647					if (matchingCallIndex >= 0) {
648						trimmed.splice(matchingCallIndex, 1);
649					}
650				}
651				continue;
652			}
653			if (!last || !shouldTrimOpenAiCompactInputItem(last)) {
654				break;
655			}
656			trimmed.pop();
657		}
658		return trimmed;
659	}
660	
661	function collectKnownOpenAiCallIds(items: Array<Record<string, unknown>>): Set<string> {
662		const knownCallIds = new Set<string>();
663		for (const item of items) {
664			if (item.type === "function_call" && typeof item.call_id === "string") {
665				knownCallIds.add(item.call_id);
666			}
667		}
668		return knownCallIds;
669	}
