671	function buildOpenAiNativeHistory(
672		messages: AgentMessage[],
673		model: Model,
674		previousReplacementHistory?: Array<Record<string, unknown>>,
675	): Array<Record<string, unknown>> {
676		const input: Array<Record<string, unknown>> = previousReplacementHistory ? [...previousReplacementHistory] : [];
677		const transformedMessages = transformMessages(convertToLlm(messages), model, id =>
678			normalizeOpenAiCompactionToolCallId(id),
679		);
680	
681		let msgIndex = 0;
682		let knownCallIds = collectKnownOpenAiCallIds(input);
683		for (const message of transformedMessages) {
684			if (message.role === "user" || message.role === "developer") {
685				const providerPayload = (message as { providerPayload?: AssistantMessage["providerPayload"] }).providerPayload;
686				const historyItems = getOpenAIResponsesHistoryItems(providerPayload, model.provider);
687				if (historyItems) {
688					input.push(...historyItems);
689					knownCallIds = collectKnownOpenAiCallIds(input);
690					msgIndex++;
691					continue;
692				}
693	
694				const contentBlocks: Array<Record<string, unknown>> = [];
695				if (typeof message.content === "string") {
696					if (message.content.trim().length > 0) {
697						contentBlocks.push({ type: "input_text", text: message.content.toWellFormed() });
698					}
699				} else {
700					for (const block of message.content) {
701						if (block.type === "text") {
702							if (!block.text || block.text.trim().length === 0) continue;
703							contentBlocks.push({ type: "input_text", text: block.text.toWellFormed() });
704							continue;
705						}
706						if (block.type === "image") {
707							contentBlocks.push({
708								type: "input_image",
709								detail: "auto",
710								image_url: `data:${block.mimeType};base64,${block.data}`,
711							});
712						}
713					}
714				}
715				if (contentBlocks.length > 0) {
716					input.push({ type: "message", role: message.role, content: contentBlocks });
717				}
718				msgIndex++;
719				continue;
720			}
721	
722			if (message.role === "assistant") {
723				const assistant = message as AssistantMessage;
724				const providerPayload = getOpenAIResponsesHistoryPayload(
725					assistant.providerPayload,
726					model.provider,
727					assistant.provider,
728				);
729				if (providerPayload) {
730					if (providerPayload.dt) {
731						input.push(...providerPayload.items);
732					} else {
733						input.splice(0, input.length, ...providerPayload.items);
734					}
735					knownCallIds = collectKnownOpenAiCallIds(input);
736					msgIndex++;
737					continue;
738				}
739				const isDifferentModel =
740					assistant.model !== model.id && assistant.provider === model.provider && assistant.api === model.api;
741	
742				for (const block of assistant.content) {
743					if (block.type === "thinking" && assistant.stopReason !== "error" && block.thinkingSignature) {
744						try {
745							const reasoningItem = JSON.parse(block.thinkingSignature) as Record<string, unknown>;
746							if (reasoningItem && typeof reasoningItem === "object") {
747								input.push(reasoningItem);
748							}
749						} catch {
750							logger.warn("Failed to parse assistant reasoning for remote compaction", {
751								model: assistant.model,
752								provider: assistant.provider,
753							});
754						}
755						continue;
756					}
757	
758					if (block.type === "text") {
759						if (!block.text || block.text.trim().length === 0) continue;
760						const parsedSignature = parseTextSignature(block.textSignature);
761						let msgId = parsedSignature?.id;
762						if (!msgId) {
763							msgId = `msg_${msgIndex}`;
764						} else if (msgId.length > 64) {
765							msgId = `msg_${Bun.hash.xxHash64(msgId).toString(36)}`;
766						}
767						input.push({
768							type: "message",
769							role: "assistant",
770							content: [{ type: "output_text", text: block.text.toWellFormed(), annotations: [] }],
771							status: "completed",
772							id: msgId,
773							phase: parsedSignature?.phase,
774						});
775						continue;
776					}
777	
778					if (block.type === "toolCall") {
779						const normalized = normalizeResponsesToolCallId(block.id);
780						let itemId: string | undefined = normalized.itemId;
781						if (isDifferentModel && (itemId?.startsWith("fc_") || itemId?.startsWith("fcr_"))) {
782							itemId = undefined;
783						}
784						knownCallIds.add(normalized.callId);
785						input.push({
786							type: "function_call",
787							id: itemId,
788							call_id: normalized.callId,
789							name: block.name,
790							arguments: JSON.stringify(block.arguments),
791						});
792					}
793				}
794	
795				msgIndex++;
796				continue;
797			}
798	
799			if (message.role === "toolResult") {
800				const normalized = normalizeResponsesToolCallId(message.toolCallId);
801				if (!knownCallIds.has(normalized.callId)) {
802					msgIndex++;
803					continue;
804				}
805	
806				const textOutput = message.content
807					.filter(block => block.type === "text")
808					.map(block => block.text)
809					.join("\n");
810				const hasImages = message.content.some(block => block.type === "image");
811				input.push({
812					type: "function_call_output",
813					call_id: normalized.callId,
814					output: (textOutput.length > 0 ? textOutput : "(see attached image)").toWellFormed(),
815				});
816	
817				if (hasImages && model.input.includes("image")) {
818					const contentBlocks: Array<Record<string, unknown>> = [
819						{ type: "input_text", text: "Attached image(s) from tool result:" },
820					];
821					for (const block of message.content) {
822						if (block.type !== "image") continue;
823						contentBlocks.push({
824							type: "input_image",
825							detail: "auto",
826							image_url: `data:${block.mimeType};base64,${block.data}`,
827						});
828					}
829					input.push({ type: "message", role: "user", content: contentBlocks });
830				}
831			}
832	
833			msgIndex++;
834		}
835	
836		return input;
837	}
838	
839	async function requestOpenAiRemoteCompaction(
840		model: Model,
841		apiKey: string,
842		compactInput: Array<Record<string, unknown>>,
843		instructions: string,
844	): Promise<OpenAiRemoteCompactionResponse> {
845		const endpoint = resolveOpenAiCompactEndpoint(model);
846		const request: OpenAiRemoteCompactionRequest = {
847			model: model.id,
848			input: trimOpenAiCompactInput(compactInput, model.contextWindow, instructions),
849			instructions,
850		};
851		const headers: Record<string, string> = {
852			"content-type": "application/json",
853			Authorization: `Bearer ${apiKey}`,
854			...(model.headers ?? {}),
855		};
856	
857		// Codex endpoints require additional auth headers
858		if (model.provider === "openai-codex") {
859			const accountId = getCodexAccountId(apiKey);
860			if (accountId) {
861				headers[OPENAI_HEADERS.ACCOUNT_ID] = accountId;
862			}
863			headers[OPENAI_HEADERS.BETA] = OPENAI_HEADER_VALUES.BETA_RESPONSES;
864			headers[OPENAI_HEADERS.ORIGINATOR] = OPENAI_HEADER_VALUES.ORIGINATOR_CODEX;
865		}
866	
867		const response = await fetch(endpoint, {
868			method: "POST",
869			headers,
870			body: JSON.stringify(request),
871		});
872	
873		if (!response.ok) {
874			const errorText = await response.text().catch(() => "");
875			logger.warn("OpenAI remote compaction failed", {
876				endpoint,
877				status: response.status,
878				statusText: response.statusText,
879				errorText,
880			});
881			throw new Error(`Remote compaction failed (${response.status} ${response.statusText})`);
882		}
883	
884		const data = (await response.json()) as { output?: unknown[] } | undefined;
885		const rawOutput = data?.output ?? [];
886		const replacementHistory = rawOutput.filter(
887			(item): item is Record<string, unknown> =>
888				!!item && typeof item === "object" && shouldKeepOpenAiCompactOutputItem(item as Record<string, unknown>),
889		);
890		const compactionItem = [...replacementHistory].reverse().find((item): item is OpenAiRemoteCompactionItem => {
891			if (item.type === "compaction" && typeof item.encrypted_content === "string") return true;
892			if (item.type === "compaction_summary") return true;
893			return false;
894		});
895		if (!compactionItem) {
896			const outputTypes = rawOutput.map(item =>
897				typeof item === "object" && item !== null ? (item as Record<string, unknown>).type : typeof item,
898			);
899			logger.warn("Remote compaction response missing compaction item", {
900				endpoint,
901				model: model.id,
902				provider: model.provider,
903				rawOutputLength: rawOutput.length,
904				outputTypes,
905				replacementHistoryLength: replacementHistory.length,
906			});
907			throw new Error("Remote compaction response missing compaction item");
908		}
909		return { provider: model.provider, replacementHistory, compactionItem };
910	}
