912	interface RemoteCompactionRequest {
913		systemPrompt: string;
914		prompt: string;
915	}
916	
917	async function requestRemoteCompaction(
918		endpoint: string,
919		request: RemoteCompactionRequest,
920	): Promise<RemoteCompactionResponse> {
921		const response = await fetch(endpoint, {
922			method: "POST",
923			headers: { "content-type": "application/json" },
924			body: JSON.stringify(request),
925		});
926	
927		if (!response.ok) {
928			const errorText = await response.text().catch(() => "");
929			logger.warn("Remote compaction failed", {
930				endpoint,
931				status: response.status,
932				statusText: response.statusText,
933				errorText,
934			});
935			throw new Error(`Remote compaction failed (${response.status} ${response.statusText})`);
936		}
937	
938		const data = (await response.json()) as RemoteCompactionResponse | undefined;
939		if (!data || typeof data.summary !== "string") {
940			throw new Error("Remote compaction response missing summary");
941		}
942	
943		return data;
944	}
