946	/**
947	 * Generate a summary of the conversation using the LLM.
948	 * If previousSummary is provided, uses the update prompt to merge.
949	 */
950	export interface SummaryOptions {
951		promptOverride?: string;
952		extraContext?: string[];
953		remoteEndpoint?: string;
954		remoteInstructions?: string;
955		initiatorOverride?: MessageAttribution;
956	}
957	
958	export async function generateSummary(
959		currentMessages: AgentMessage[],
960		model: Model,
961		reserveTokens: number,
962		apiKey: string,
963		signal?: AbortSignal,
964		customInstructions?: string,
965		previousSummary?: string,
966		options?: SummaryOptions,
967	): Promise<string> {
968		const maxTokens = Math.floor(0.8 * reserveTokens);
969	
970		// Use update prompt if we have a previous summary, otherwise initial prompt
971		let basePrompt = previousSummary ? UPDATE_SUMMARIZATION_PROMPT : SUMMARIZATION_PROMPT;
972		if (options?.promptOverride) {
973			basePrompt = options.promptOverride;
974		}
975		if (customInstructions) {
976			basePrompt = `${basePrompt}\n\nAdditional focus: ${customInstructions}`;
977		}
978	
979		// Serialize conversation to text so model doesn't try to continue it
980		// Convert to LLM messages first (handles custom types like bashExecution, hookMessage, etc.)
981		const llmMessages = convertToLlm(currentMessages);
982		const conversationText = serializeConversation(llmMessages);
983	
984		// Build the prompt with conversation wrapped in tags
985		let promptText = `<conversation>\n${conversationText}\n</conversation>\n\n`;
986		if (previousSummary) {
987			promptText += `<previous-summary>\n${previousSummary}\n</previous-summary>\n\n`;
988		}
989		promptText += formatAdditionalContext(options?.extraContext);
990		promptText += basePrompt;
991	
992		const summarizationMessages = [
993			{
994				role: "user" as const,
995				content: [{ type: "text" as const, text: promptText }],
996				timestamp: Date.now(),
997			},
998		];
999	
1000		if (options?.remoteEndpoint) {
1001			const remote = await requestRemoteCompaction(options.remoteEndpoint, {
1002				systemPrompt: SUMMARIZATION_SYSTEM_PROMPT,
1003				prompt: promptText,
1004			});
1005			return remote.summary;
1006		}
1007	
1008		const response = await completeSimple(
1009			model,
1010			{ systemPrompt: SUMMARIZATION_SYSTEM_PROMPT, messages: summarizationMessages },
1011			{ maxTokens, signal, apiKey, reasoning: Effort.High, initiatorOverride: options?.initiatorOverride },
1012		);
1013	
1014		if (response.stopReason === "error") {
1015			throw new Error(`Summarization failed: ${response.errorMessage || "Unknown error"}`);
1016		}
1017	
1018		const textContent = response.content
1019			.filter((c): c is { type: "text"; text: string } => c.type === "text")
1020			.map(c => c.text)
1021			.join("\n");
1022	
1023		return textContent;
1024	}
1025	
1026	async function generateShortSummary(
1027		recentMessages: AgentMessage[],
1028		historySummary: string | undefined,
1029		model: Model,
1030		reserveTokens: number,
1031		apiKey: string,
1032		signal?: AbortSignal,
1033		options?: SummaryOptions,
1034	): Promise<string> {
1035		const maxTokens = Math.min(512, Math.floor(0.2 * reserveTokens));
1036		const llmMessages = convertToLlm(recentMessages);
1037		const conversationText = serializeConversation(llmMessages);
1038	
1039		let promptText = `<conversation>\n${conversationText}\n</conversation>\n\n`;
1040		if (historySummary) {
1041			promptText += `<previous-summary>\n${historySummary}\n</previous-summary>\n\n`;
1042		}
1043		promptText += formatAdditionalContext(options?.extraContext);
1044		promptText += SHORT_SUMMARY_PROMPT;
1045	
1046		if (options?.remoteEndpoint) {
1047			const remote = await requestRemoteCompaction(options.remoteEndpoint, {
1048				systemPrompt: SUMMARIZATION_SYSTEM_PROMPT,
1049				prompt: promptText,
1050			});
1051			return remote.summary;
1052		}
1053	
1054		const response = await completeSimple(
1055			model,
1056			{
1057				systemPrompt: SUMMARIZATION_SYSTEM_PROMPT,
1058				messages: [{ role: "user", content: [{ type: "text", text: promptText }], timestamp: Date.now() }],
1059			},
1060			{ maxTokens, signal, apiKey, reasoning: Effort.High, initiatorOverride: options?.initiatorOverride },
1061		);
1062	
1063		if (response.stopReason === "error") {
1064			throw new Error(`Short summary failed: ${response.errorMessage || "Unknown error"}`);
1065		}
1066	
1067		return response.content
1068			.filter((c): c is { type: "text"; text: string } => c.type === "text")
1069			.map(c => c.text)
1070			.join("\n");
1071	}
1072	
1073	// ============================================================================
1074	// Compaction Preparation (for hooks)
1075	// ============================================================================
1076	
1077	export interface CompactionPreparation {
1078		/** UUID of first entry to keep */
1079		firstKeptEntryId: string;
1080		/** Messages that will be summarized and discarded */
1081		messagesToSummarize: AgentMessage[];
1082		/** Messages that will be turned into turn prefix summary (if splitting) */
1083		turnPrefixMessages: AgentMessage[];
1084		/** Messages kept in full after compaction (recent history) */
1085		recentMessages: AgentMessage[];
1086		/** Whether this is a split turn (cut point in middle of turn) */
1087		isSplitTurn: boolean;
1088		tokensBefore: number;
1089		/** Summary from previous compaction, for iterative update */
1090		previousSummary?: string;
1091		/** Preserved opaque compaction payload from the previous compaction, if any. */
1092		previousPreserveData?: Record<string, unknown>;
1093		/** File operations extracted from messagesToSummarize */
1094		fileOps: FileOperations;
1095		/** Compaction settions from settings.jsonl	*/
1096		settings: CompactionSettings;
1097	}
1098	
1099	export function prepareCompaction(
1100		pathEntries: SessionEntry[],
1101		settings: CompactionSettings,
1102	): CompactionPreparation | undefined {
1103		if (pathEntries.length > 0 && pathEntries[pathEntries.length - 1].type === "compaction") {
1104			return undefined;
1105		}
1106	
1107		let prevCompactionIndex = -1;
1108		for (let i = pathEntries.length - 1; i >= 0; i--) {
1109			if (pathEntries[i].type === "compaction") {
1110				prevCompactionIndex = i;
1111				break;
1112			}
1113		}
1114		const boundaryStart = prevCompactionIndex + 1;
1115		const boundaryEnd = pathEntries.length;
1116	
1117		const lastUsage = getLastAssistantUsage(pathEntries);
1118		const tokensBefore = lastUsage ? calculateContextTokens(lastUsage) : 0;
1119		let keepRecentTokens = settings.keepRecentTokens;
1120		if (lastUsage) {
1121			const estimatedTokens = estimateEntriesTokens(pathEntries, boundaryStart, boundaryEnd);
1122			const promptTokens = calculatePromptTokens(lastUsage);
1123			const ratio = estimatedTokens > 0 ? promptTokens / estimatedTokens : 0;
1124			if (Number.isFinite(ratio) && ratio > 1) {
1125				keepRecentTokens = Math.max(1, Math.floor(keepRecentTokens / ratio));
1126			}
1127		}
1128	
1129		const cutPoint = findCutPoint(pathEntries, boundaryStart, boundaryEnd, keepRecentTokens);
1130	
1131		// Get ID of first kept entry
1132		const firstKeptEntry = pathEntries[cutPoint.firstKeptEntryIndex];
1133		if (!firstKeptEntry?.id) {
1134			return undefined; // Session needs migration
1135		}
1136		const firstKeptEntryId = firstKeptEntry.id;
1137	
1138		const historyEnd = cutPoint.isSplitTurn ? cutPoint.turnStartIndex : cutPoint.firstKeptEntryIndex;
1139	
1140		// Messages to summarize (will be discarded after summary)
1141		const messagesToSummarize: AgentMessage[] = [];
1142		for (let i = boundaryStart; i < historyEnd; i++) {
1143			const msg = getMessageFromEntry(pathEntries[i]);
1144			if (msg) messagesToSummarize.push(msg);
1145		}
1146	
1147		// Messages for turn prefix summary (if splitting a turn)
1148		const turnPrefixMessages: AgentMessage[] = [];
1149		if (cutPoint.isSplitTurn) {
1150			for (let i = cutPoint.turnStartIndex; i < cutPoint.firstKeptEntryIndex; i++) {
1151				const msg = getMessageFromEntry(pathEntries[i]);
1152				if (msg) turnPrefixMessages.push(msg);
1153			}
1154		}
1155	
1156		// Messages kept after compaction (recent history)
1157		const recentMessages: AgentMessage[] = [];
1158		for (let i = cutPoint.firstKeptEntryIndex; i < boundaryEnd; i++) {
1159			const msg = getMessageFromEntry(pathEntries[i]);
1160			if (msg) recentMessages.push(msg);
1161		}
1162		// Nothing to summarize means compaction would be a no-op.
1163		if (messagesToSummarize.length === 0 && turnPrefixMessages.length === 0) {
1164			return undefined;
1165		}
1166	
1167		// Get previous summary and preserved data for iterative updates
1168		let previousSummary: string | undefined;
1169		let previousPreserveData: Record<string, unknown> | undefined;
1170		if (prevCompactionIndex >= 0) {
1171			const prevCompaction = pathEntries[prevCompactionIndex] as CompactionEntry;
1172			previousSummary = prevCompaction.summary;
1173			previousPreserveData = prevCompaction.preserveData;
1174		}
1175	
1176		// Extract file operations from messages and previous compaction
1177		const fileOps = extractFileOperations(messagesToSummarize, pathEntries, prevCompactionIndex);
1178	
1179		// Also extract file ops from turn prefix if splitting
1180		if (cutPoint.isSplitTurn) {
1181			for (const msg of turnPrefixMessages) {
1182				extractFileOpsFromMessage(msg, fileOps);
1183			}
1184		}
1185	
1186		return {
1187			firstKeptEntryId,
1188			messagesToSummarize,
1189			turnPrefixMessages,
1190			recentMessages,
1191			isSplitTurn: cutPoint.isSplitTurn,
1192			tokensBefore,
1193			previousSummary,
1194			previousPreserveData,
1195			fileOps,
1196			settings,
1197		};
1198	}
1199	
1200	// ============================================================================
1201	// Main compaction function
1202	// ============================================================================
1203	
1204	const TURN_PREFIX_SUMMARIZATION_PROMPT = renderPromptTemplate(compactionTurnPrefixPrompt);
1205	
1206	/**
1207	 * Generate summaries for compaction using prepared data.
1208	 * Returns CompactionResult - SessionManager adds id/parentId when saving.
1209	 *
1210	 * @param preparation - Pre-calculated preparation from prepareCompaction()
1211	 * @param customInstructions - Optional custom focus for the summary
1212	 */
1213	export async function compact(
1214		preparation: CompactionPreparation,
1215		model: Model,
1216		apiKey: string,
1217		customInstructions?: string,
1218		signal?: AbortSignal,
1219		options?: SummaryOptions,
1220	): Promise<CompactionResult> {
1221		const {
1222			firstKeptEntryId,
1223			messagesToSummarize,
1224			turnPrefixMessages,
1225			recentMessages,
1226			isSplitTurn,
1227			tokensBefore,
1228			previousSummary,
1229			previousPreserveData,
1230			fileOps,
1231			settings,
1232		} = preparation;
1233	
1234		const summaryOptions: SummaryOptions = {
1235			promptOverride: options?.promptOverride,
1236			extraContext: options?.extraContext,
1237			remoteEndpoint: settings.remoteEnabled === false ? undefined : settings.remoteEndpoint,
1238			remoteInstructions: options?.remoteInstructions,
1239			initiatorOverride: options?.initiatorOverride,
1240		};
1241	
1242		let preserveData = withOpenAiRemoteCompactionPreserveData(previousPreserveData, undefined);
1243		if (settings.remoteEnabled !== false && shouldUseOpenAiRemoteCompaction(model)) {
1244			const previousRemoteCompaction = getPreservedOpenAiRemoteCompactionData(previousPreserveData);
1245			const remoteMessages = [...messagesToSummarize, ...turnPrefixMessages, ...recentMessages];
1246			const previousReplacementHistory =
1247				previousRemoteCompaction?.provider === model.provider
1248					? previousRemoteCompaction.replacementHistory
1249					: undefined;
1250			const remoteHistory = buildOpenAiNativeHistory(remoteMessages, model, previousReplacementHistory);
1251			if (remoteHistory.length > 0) {
1252				try {
1253					const remote = await requestOpenAiRemoteCompaction(
1254						model,
1255						apiKey,
1256						remoteHistory,
1257						summaryOptions.remoteInstructions ?? SUMMARIZATION_SYSTEM_PROMPT,
1258					);
1259					preserveData = withOpenAiRemoteCompactionPreserveData(previousPreserveData, remote);
1260				} catch (err) {
1261					logger.warn("OpenAI remote compaction failed, falling back to local summarization", {
1262						error: err instanceof Error ? err.message : String(err),
1263						model: model.id,
1264						provider: model.provider,
1265					});
1266				}
1267			}
1268		}
1269	
1270		// Generate summaries (can be parallel if both needed) and merge into one
1271		let summary: string;
1272	
1273		if (isSplitTurn && turnPrefixMessages.length > 0) {
1274			// Generate both summaries in parallel
1275			const [historyResult, turnPrefixResult] = await Promise.all([
1276				messagesToSummarize.length > 0
1277					? generateSummary(
1278							messagesToSummarize,
1279							model,
1280							settings.reserveTokens,
1281							apiKey,
1282							signal,
1283							customInstructions,
1284							previousSummary,
1285							summaryOptions,
1286						)
1287					: Promise.resolve("No prior history."),
1288				generateTurnPrefixSummary(
1289					turnPrefixMessages,
1290					model,
1291					settings.reserveTokens,
1292					apiKey,
1293					signal,
1294					summaryOptions.initiatorOverride,
1295				),
1296			]);
1297			// Merge into single summary
1298			summary = `${historyResult}\n\n---\n\n**Turn Context (split turn):**\n\n${turnPrefixResult}`;
1299		} else if (messagesToSummarize.length > 0) {
1300			// Generate history summary from messages to summarize
1301			summary = await generateSummary(
1302				messagesToSummarize,
1303				model,
1304				settings.reserveTokens,
1305				apiKey,
1306				signal,
1307				customInstructions,
1308				previousSummary,
1309				summaryOptions,
1310			);
1311		} else if (previousSummary) {
1312			// No new messages to summarize, preserve previous summary
1313			summary = previousSummary;
1314		} else {
1315			// No messages and no previous summary
1316			summary = "No prior history.";
1317		}
1318	
1319		const shortSummary = await generateShortSummary(
1320			recentMessages,
1321			summary,
1322			model,
1323			settings.reserveTokens,
1324			apiKey,
1325			signal,
1326			{
1327				extraContext: options?.extraContext,
1328				remoteEndpoint: summaryOptions.remoteEndpoint,
1329				initiatorOverride: summaryOptions.initiatorOverride,
1330			},
1331		);
1332	
1333		// Compute file lists and append to summary
1334		const { readFiles, modifiedFiles } = computeFileLists(fileOps);
1335		summary = upsertFileOperations(summary, readFiles, modifiedFiles);
1336	
1337		if (!firstKeptEntryId) {
1338			throw new Error("First kept entry has no ID - session may need migration");
1339		}
1340	
1341		return {
1342			summary,
1343			shortSummary,
1344			firstKeptEntryId,
1345			tokensBefore,
1346			details: { readFiles, modifiedFiles } as CompactionDetails,
1347			preserveData,
1348		};
1349	}
1350	
1351	/**
1352	 * Generate a summary for a turn prefix (when splitting a turn).
1353	 */
1354	async function generateTurnPrefixSummary(
1355		messages: AgentMessage[],
1356		model: Model,
1357		reserveTokens: number,
1358		apiKey: string,
1359		signal?: AbortSignal,
1360		initiatorOverride?: MessageAttribution,
1361	): Promise<string> {
1362		const maxTokens = Math.floor(0.5 * reserveTokens); // Smaller budget for turn prefix
1363	
1364		const llmMessages = convertToLlm(messages);
1365		const conversationText = serializeConversation(llmMessages);
1366		const promptText = `<conversation>\n${conversationText}\n</conversation>\n\n${TURN_PREFIX_SUMMARIZATION_PROMPT}`;
1367		const summarizationMessages = [
1368			{
1369				role: "user" as const,
1370				content: [{ type: "text" as const, text: promptText }],
1371				timestamp: Date.now(),
1372			},
1373		];
1374	
1375		const response = await completeSimple(
1376			model,
1377			{ systemPrompt: SUMMARIZATION_SYSTEM_PROMPT, messages: summarizationMessages },
1378			{ maxTokens, signal, apiKey, reasoning: Effort.High, initiatorOverride },
1379		);
1380	
1381		if (response.stopReason === "error") {
1382			throw new Error(`Turn prefix summarization failed: ${response.errorMessage || "Unknown error"}`);
1383		}
1384	
1385		return response.content
1386			.filter((c): c is { type: "text"; text: string } => c.type === "text")
1387			.map(c => c.text)
1388			.join("\n");
1389	}
